import { scope } from "arktype";

// Define the recursive DirectoryTree type using scope().export()
// A node has:
//   name: non-empty string (required)
//   size: positive integer (optional, only on files)
//   children: array of DirectoryTree nodes (optional, only on directories)
// Only directories may have children; files (with size) must not have children.

const DirectoryTreeModule = scope({
  DirectoryTree: {
    name: "string > 0", // non-empty string
    "size?": "integer > 0", // optional positive integer (file indicator)
    "children?": "DirectoryTree[]", // optional recursive children (directory indicator)
  },
}).export();

// Export the validateDirectoryTree function
export function validateDirectoryTree(input: unknown) {
  return DirectoryTreeModule.DirectoryTree.assert(input);
}

