cd /home/user/myproject && npx tsx -e "
import { scope } from 'arktype';

const DirectoryTreeModule = scope({
  DirectoryTree: {
    name: 'string > 0',
    'size?': 'integer > 0',
    'children?': 'DirectoryTree[]',
  },
}).export();

// Test 1: Valid 4-level nested tree
const validTree = {
  name: 'root',
  children: [{
    name: 'dir1',
    children: [{
      name: 'dir2',
      children: [{
        name: 'file.txt',
        size: 1024
      }]
    }]
  }]
};

try {
  const result = DirectoryTreeModule.DirectoryTree.assert(validTree);
  console.log('Test 1 (valid tree): PASS', JSON.stringify(result));
} catch (e: any) {
  console.log('Test 1 (valid tree): FAIL', e.message);
}

// Test 2: Missing name
try {
  DirectoryTreeModule.DirectoryTree.assert({ size: 100 });
  console.log('Test 2 (missing name): FAIL - should have thrown');
} catch (e: any) {
  console.log('Test 2 (missing name): PASS', e.message);
}

